// LoggingController.java
package com.example.logging;

import jakarta.ws.rs.*;
import jakarta.ws.rs.core.*;
import org.tinylog.Logger;

@Path("/log")
@Produces(MediaType.APPLICATION_JSON)
@Consumes(MediaType.APPLICATION_JSON)
public class LoggingController {

    @POST
    @Path("/info")
    public Response logInfo(LogMessage logMessage) {
        validate(logMessage);
        Logger.info(logMessage.getMessage());
        return Response.ok(new LogResponse("INFO logged")).build();
    }

    @POST
    @Path("/debug")
    public Response logDebug(LogMessage logMessage) {
        validate(logMessage);
        Logger.debug(logMessage.getMessage());
        return Response.ok(new LogResponse("DEBUG logged")).build();
    }

    @POST
    @Path("/error")
    public Response logError(LogMessage logMessage) {
        validate(logMessage);
        Logger.error(logMessage.getMessage());
        return Response.ok(new LogResponse("ERROR logged")).build();
    }

    private void validate(LogMessage logMessage) {
        if (logMessage == null || logMessage.getMessage() == null || logMessage.getMessage().trim().isEmpty()) {
            throw new WebApplicationException(
                Response.status(Response.Status.BAD_REQUEST)
                        .entity(new ErrorResponse("Message required"))
                        .build()
            );
        }
    }
}

