// LoggingExceptionMapper.java
package com.example.logging;

import jakarta.ws.rs.WebApplicationException;
import jakarta.ws.rs.core.Response;
import jakarta.ws.rs.ext.ExceptionMapper;
import jakarta.ws.rs.ext.Provider;

@Provider
public class LoggingExceptionMapper implements ExceptionMapper<Throwable> {
    @Override
    public Response toResponse(Throwable ex) {
        int status = ex instanceof WebApplicationException ? 
            ((WebApplicationException) ex).getResponse().getStatus() : 500;
        String msg = ex.getMessage();
        return Response.status(status).entity(new ErrorResponse(msg != null ? msg : "Logging failed")).build();
    }
}

