// LibraryServer.java
package com.example.library;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.Status;
import io.grpc.StatusRuntimeException;
import java.util.concurrent.ConcurrentHashMap;

public class LibraryServer {
  private static final ConcurrentHashMap<String, Book> books = new ConcurrentHashMap<>();

  public static void main(String[] args) throws Exception {
    Server server = ServerBuilder.forPort(50051)
        .addService(new LibraryServiceImpl())
        .build();
    server.start();
    server.awaitTermination();
  }

  static class LibraryServiceImpl extends LibraryServiceGrpc.LibraryServiceImplBase {
    @Override
    public void addBook(Book request, io.grpc.stub.StreamObserver<BookResponse> responseObserver) {
      books.put(request.getId(), request);
      responseObserver.onNext(BookResponse.newBuilder()
          .setId(request.getId())
          .setMessage("Book added successfully")
          .build());
      responseObserver.onCompleted();
    }

    @Override
    public void getBook(BookRequest request, io.grpc.stub.StreamObserver<Book> responseObserver) {
      Book book = books.get(request.getId());
      if (book == null) {
        responseObserver.onError(new StatusRuntimeException(Status.NOT_FOUND
            .withDescription("Book not found")));
        return;
      }
      responseObserver.onNext(book);
      responseObserver.onCompleted();
    }

    @Override
    public void deleteBook(BookRequest request, io.grpc.stub.StreamObserver<BookResponse> responseObserver) {
      Book book = books.remove(request.getId());
      if (book == null) {
        responseObserver.onError(new StatusRuntimeException(Status.NOT_FOUND
            .withDescription("Book not found")));
        return;
      }
      responseObserver.onNext(BookResponse.newBuilder()
          .setId(request.getId())
          .setMessage("Book deleted successfully")
          .build());
      responseObserver.onCompleted();
    }
  }
}
