package com.example.library;

import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;

public class LibraryClient {
  public static void main(String[] args) {
    ManagedChannel channel = ManagedChannelBuilder.forAddress("localhost", 50051)
        .usePlaintext()
        .build();
    LibraryServiceGrpc.LibraryServiceBlockingStub stub = LibraryServiceGrpc.newBlockingStub(channel);

    try {
      // Add a book
      Book addedBook = Book.newBuilder()
          .setId("1")
          .setTitle("Effective Java")
          .setAuthor("Joshua Bloch")
          .setIsbn("0134685997")
          .build();
      stub.addBook(addedBook);

      // Get a book
      Book book = stub.getBook(BookRequest.newBuilder().setId("1").build());
      System.out.println("Retrieved book: " + book.getTitle());

      // Delete a book
      stub.deleteBook(BookRequest.newBuilder().setId("1").build());

      // Try to get deleted book (should error)
      stub.getBook(BookRequest.newBuilder().setId("1").build());
    } catch (StatusRuntimeException e) {
      System.err.println("Error: " + e.getStatus().getDescription());
    }
    channel.shutdown();
  }
}
