use serde::{Deserialize, Serialize};
use std::sync::Mutex;

#[derive(Serialize, Deserialize, Clone)]
struct Item {
    name: String,
}

struct AppState {
    items: Mutex<Vec<Item>>,
}

async fn get_items(data: web::Data<AppState>) -> impl Responder {
    let items = data.items.lock().unwrap();
    HttpResponse::Ok().json(&*items)
}

async fn add_item(data: web::Data<AppState>, item: web::Json<Item>) -> Result<HttpResponse> {
    if item.name.trim().is_empty() {
        return Ok(HttpResponse::BadRequest().json("Item name cannot be empty"));
    }

    let mut items = data.items.lock().unwrap();
    items.push(item.into_inner());
    Ok(HttpResponse::Created().json(items.last().unwrap()))
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| {
        App::new()
            .app_data(web::Data::new(AppState {
                items: Mutex::new(Vec::new()),
            }))
            .service(
                web::resource("/items")
                    .route(web::get().to(get_items))
                    .route(web::post().to(add_item)),
            )
    })
    .bind("0.0.0.0:8080")?
    .run()
    .await
}
