// UserStore.java
import org.tinylog.Logger;
import java.util.HashMap;
import java.util.Map;

public class UserStore {
    private final Map<String, User> users = new HashMap<>();

    public void createUser(User user) {
        try {
            if (users.containsKey(user.getId())) {
                throw new IllegalArgumentException("User ID exists: " + user.getId());
            }
            users.put(user.getId(), user);
            Logger.info("Created user: {}", user.getId());
        } catch (Exception e) {
            Logger.error(e, "Failed to create user");
            throw e;
        }
    }

    public User getUser(String id) {
        try {
            User user = users.get(id);
            if (user == null) {
                throw new IllegalArgumentException("User not found: " + id);
            }
            Logger.info("Retrieved user: {}", id);
            return user;
        } catch (Exception e) {
            Logger.error(e, "Failed to retrieve user");
            throw e;
        }
    }

    public void updateUser(User user) {
        try {
            if (!users.containsKey(user.getId())) {
                throw new IllegalArgumentException("User not found: " + user.getId());
            }
            users.put(user.getId(), user);
            Logger.info("Updated user: {}", user.getId());
        } catch (Exception e) {
            Logger.error(e, "Failed to update user");
            throw e;
        }
    }

    public void deleteUser(String id) {
        try {
            if (!users.containsKey(id)) {
                throw new IllegalArgumentException("User not found: " + id);
            }
            users.remove(id);
            Logger.info("Deleted user: {}", id);
        } catch (Exception e) {
            Logger.error(e, "Failed to delete user");
            throw e;
        }
    }
}

