from cornice import Service
from cornice.validators import colander_body_validator
from pyramid.config import Configurator
from pyramid.response import Response
from colander import MappingSchema, SchemaNode, String, Integer, Range

books = []
id_counter = 1

class BookSchema(MappingSchema):
    title = SchemaNode(String())
    author = SchemaNode(String())
    publication_year = SchemaNode(Integer(), validator=Range(min=0, max=9999))

book_collection = Service(name='books', path='/books')
book_item = Service(name='book', path='/books/{id}')

@book_collection.post(schema=BookSchema(), validators=(colander_body_validator,))
def create_book(request):
    global id_counter
    book = request.validated
    book['id'] = id_counter
    books.append(book)
    id_counter += 1
    return Response(status=201, json=book)

@book_collection.get()
def list_books(request):
    return {'books': books}

@book_item.get()
def get_book(request):
    id = int(request.matchdict['id'])
    book = next((b for b in books if b['id'] == id), None)
    if not book:
        request.errors.add('url', 'id', 'Book not found')
        return Response(status=404)
    return book

@book_item.put(schema=BookSchema(), validators=(colander_body_validator,))
def update_book(request):
    id = int(request.matchdict['id'])
    book = next((b for b in books if b['id'] == id), None)
    if not book:
        request.errors.add('url', 'id', 'Book not found')
        return Response(status=404)
    book.update(request.validated)
    return book

@book_item.delete()
def delete_book(request):
    id = int(request.matchdict['id'])
    global books
    books = [b for b in books if b['id'] != id]
    return Response(status=204)

def includeme(config):
    config.include("cornice")
    config.scan()

if __name__ == '__main__':
    config = Configurator()
    config.include(includeme)
    app = config.make_wsgi_app()
    from wsgiref.simple_server import make_server
    server = make_server('0.0.0.0', 6543, app)
    server.serve_forever()
