use actix_web::{delete, get, post, put, web, App, HttpResponse, HttpServer, Result};
use chrono::Utc;
use rusqlite::{params, Connection, OptionalExtension};
use serde::{Deserialize, Serialize};
use std::sync::Mutex;
use uuid::Uuid;

#[derive(Serialize, Deserialize)]
struct Note {
    id: String,
    title: String,
    content: String,
    created_at: String,
}

#[derive(Deserialize)]
struct NoteInput {
    title: String,
    content: String,
}

struct AppState {
    db: Mutex<Connection>,
}

#[post("/notes")]
async fn create_note(data: web::Data<AppState>, input: web::Json<NoteInput>) -> Result<HttpResponse> {
    if input.title.trim().is_empty() || input.content.trim().is_empty() {
        return Ok(HttpResponse::BadRequest().json(
            serde_json::json!({"error": "Title and content must not be empty"}),
        ));
    }

    let id = Uuid::new_v4().to_string();
    let created_at = Utc::now().to_rfc3339();

    data.db.lock().unwrap().execute(
        "INSERT INTO notes (id, title, content, created_at) VALUES (?1, ?2, ?3, ?4)",
        params![&id, &input.title, &input.content, &created_at],
    )?;

    Ok(HttpResponse::Created().json(Note {
        id,
        title: input.title.clone(),
        content: input.content.clone(),
        created_at,
    }))
}

#[get("/notes")]
async fn get_notes(data: web::Data<AppState>) -> Result<HttpResponse> {
    let conn = data.db.lock().unwrap();
    let mut stmt = conn.prepare("SELECT id, title, content, created_at FROM notes")?;
    let notes = stmt
        .query_map([], |row| {
            Ok(Note {
                id: row.get(0)?,
                title: row.get(1)?,
                content: row.get(2)?,
                created_at: row.get(3)?,
            })
        })?
        .collect::<Result<Vec<_>, _>>()?;

    Ok(HttpResponse::Ok().json(notes))
}

#[get("/notes/{id}")]
async fn get_note(data: web::Data<AppState>, id: web::Path<String>) -> Result<HttpResponse> {
    let note = data
        .db
        .lock()
        .unwrap()
        .query_row(
            "SELECT id, title, content, created_at FROM notes WHERE id = ?1",
            params![&id.into_inner()],
            |row| {
                Ok(Note {
                    id: row.get(0)?,
                    title: row.get(1)?,
                    content: row.get(2)?,
                    created_at: row.get(3)?,
                })
            },
        )
        .optional()?;

    match note {
        Some(note) => Ok(HttpResponse::Ok().json(note)),
        None => Ok(HttpResponse::NotFound().json(serde_json::json!({"error": "Note not found"}))),
    }
}

#[put("/notes/{id}")]
async fn update_note(
    data: web::Data<AppState>,
    id: web::Path<String>,
    input: web::Json<NoteInput>,
) -> Result<HttpResponse> {
    if input.title.trim().is_empty() || input.content.trim().is_empty() {
        return Ok(HttpResponse::BadRequest().json(
            serde_json::json!({"error": "Title and content must not be empty"}),
        ));
    }

    let rows_affected = data.db.lock().unwrap().execute(
        "UPDATE notes SET title = ?1, content = ?2 WHERE id = ?3",
        params![&input.title, &input.content, &id.into_inner()],
    )?;

    if rows_affected == 0 {
        Ok(HttpResponse::NotFound().json(serde_json::json!({"error": "Note not found"})))
    } else {
        Ok(HttpResponse::Ok().json(serde_json::json!({"success": true})))
    }
}

#[delete("/notes/{id}")]
async fn delete_note(data: web::Data<AppState>, id: web::Path<String>) -> Result<HttpResponse> {
    let rows_affected = data.db.lock().unwrap().execute(
        "DELETE FROM notes WHERE id = ?1",
        params![&id.into_inner()],
    )?;

    if rows_affected == 0 {
        Ok(HttpResponse::NotFound().json(serde_json::json!({"error": "Note not found"})))
    } else {
        Ok(HttpResponse::Ok().json(serde_json::json!({"success": true})))
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let conn = Connection::open("notes.db").unwrap();
    conn.execute(
        "CREATE TABLE IF NOT EXISTS notes (
            id TEXT PRIMARY KEY,
            title TEXT NOT NULL,
            content TEXT NOT NULL,
            created_at TEXT NOT NULL
        )",
        [],
    )
    .unwrap();

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(AppState {
                db: Mutex::new(conn.try_clone().unwrap()),
            }))
            .service(create_note)
            .service(get_notes)
            .service(get_note)
            .service(update_note)
            .service(delete_note)
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}
