class TaskNode : public GNode {
public:
    explicit TaskNode(const std::string& name) : GNode(name) {}

    CStatus run() override {
        std::lock_guard<std::mutex> lock(io_mutex);
        std::cout << "Executing task: " << getName() << std::endl;
        return CStatus();
    }

private:
    static std::mutex io_mutex;
};

std::mutex TaskNode::io_mutex;

int main() {
    GPipelinePtr pipeline = GPipelineFactory::create();

    auto taskA = pipeline->createGNode<TaskNode>(GAccessor::EN_LOCKED, "TaskA");
    auto taskB = pipeline->createGNode<TaskNode>(GAccessor::EN_LOCKED, "TaskB");
    auto taskC = pipeline->createGNode<TaskNode>(GAccessor::EN_LOCKED, "TaskC");
    auto taskD = pipeline->createGNode<TaskNode>(GAccessor::EN_LOCKED, "TaskD");

    try {
        taskB->add_dependency(taskA);
        taskC->add_dependency(taskB);
        taskD->add_dependency(taskC);

        // Uncomment to test cycle detection
        // taskA->add_dependency(taskD);

        pipeline->registerGNode(taskA);
        pipeline->registerGNode(taskB);
        pipeline->registerGNode(taskC);
        pipeline->registerGNode(taskD);

        pipeline->init();
        pipeline->run();
        pipeline->destroy();
    }
    catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }

