package com.example.library;

import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.Status;
import io.grpc.stub.StreamObserver;
import org.apache.logging.log4j.LogManager;
import org.apache.logging.log4j.Logger;

import java.io.IOException;
import java.util.concurrent.ConcurrentHashMap;

public class LibraryServer {
    private static final Logger logger = LogManager.getLogger(LibraryServer.class);
    private final int port;
    private final Server server;

    public LibraryServer(int port) {
        this(ServerBuilder.forPort(port), port);
    }

    public LibraryServer(ServerBuilder<?> serverBuilder, int port) {
        this.port = port;
        this.server = serverBuilder.addService(new LibraryServiceImpl()).build();
    }

    public void start() throws IOException {
        server.start();
        logger.info("Server started, listening on " + port);
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.err.println("Shutting down gRPC server");
            LibraryServer.this.stop();
            System.err.println("Server shut down");
        }));
    }

    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }

    private void blockUntilShutdown() throws InterruptedException {
        if (server != null) {
            server.awaitTermination();
        }
    }

    public static void main(String[] args) throws Exception {
        LibraryServer server = new LibraryServer(50051);
        server.start();
        server.blockUntilShutdown();
    }

    static class LibraryServiceImpl extends LibraryServiceGrpc.LibraryServiceImplBase {
        private final ConcurrentHashMap<String, Book> books = new ConcurrentHashMap<>();
        private final Logger logger = LogManager.getLogger(LibraryServiceImpl.class);

        @Override
        public void addBook(Book request, StreamObserver<BookResponse> responseObserver) {
            logger.info("AddBook request received: " + request);
            books.put(request.getId(), request);
            responseObserver.onNext(BookResponse.newBuilder().setStatus("Added successfully").build());
            responseObserver.onCompleted();
        }

        @Override
        public void getBook(BookRequest request, StreamObserver<Book> responseObserver) {
            logger.info("GetBook request received for ID: " + request.getId());
            Book book = books.get(request.getId());
            if (book == null) {
                responseObserver.onError(Status.NOT_FOUND
                        .withDescription("Book not found")
                        .asRuntimeException());
                return;
            }
            responseObserver.onNext(book);
            responseObserver.onCompleted();
        }

        @Override
        public void listBooks(Empty request, StreamObserver<BookList> responseObserver) {
            logger.info("ListBooks request received");
            BookList.Builder builder = BookList.newBuilder();
            books.values().forEach(builder::addBooks);
            responseObserver.onNext(builder.build());
            responseObserver.onCompleted();
        }
    }
}
