from cornice import Service
from pyramid.config import Configurator
from pyramid.response import Response
from pyramid.view import view_config
import colander
import json
import logging
from datetime import datetime

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

BOOKS = []
NEXT_ID = 1

class BookSchema(colander.MappingSchema):
    title = colander.SchemaNode(colander.String())
    author = colander.SchemaNode(colander.String())
    isbn = colander.SchemaNode(colander.String(), missing=colander.drop)

book_service = Service(name='books', path='/books', description='Books collection')
single_book_service = Service(name='book', path='/books/{id}', description='Individual book')

@book_service.get()
def get_books(request):
    return {'books': BOOKS}

@book_service.post(schema=BookSchema)
def create_book(request):
    global NEXT_ID
    book = request.validated
    book['id'] = NEXT_ID
    NEXT_ID += 1
    BOOKS.append(book)
    return Response(status=201, json_body=book)

@single_book_service.get()
def get_book(request):
    id = int(request.matchdict['id'])
    book = next((b for b in BOOKS if b['id'] == id), None)
    if not book:
        return Response(status=404, json_body={'error': 'Book not found'})
    return book

@single_book_service.put(schema=BookSchema)
def update_book(request):
    id = int(request.matchdict['id'])
    book_data = request.validated
    index = next((i for i, b in enumerate(BOOKS) if b['id'] == id), -1)
    if index == -1:
        return Response(status=404, json_body={'error': 'Book not found'})
    book_data['id'] = id
    BOOKS[index] = book_data
    return book_data

@single_book_service.delete()
def delete_book(request):
    id = int(request.matchdict['id'])
    global BOOKS
    BOOKS = [b for b in BOOKS if b['id'] != id]
    return Response(status=204)

def log_tween(handler, registry):
    def tween(request):
        timestamp = datetime.now().isoformat()
        logger.info(f"{timestamp} - {request.method} {request.path}")
        return handler(request)
    return tween

def main(global_config, **settings):
    config = Configurator(settings=settings)
    config.include('cornice')
    config.add_tween('__main__.log_tween')
    config.scan()
    return config.make_wsgi_app()

if __name__ == '__main__':
    from waitress import serve
    app = main({})
    serve(app, host='0.0.0.0', port=6543)
