from flask import Flask, jsonify, request, abort, make_response
from datetime import datetime

app = Flask(__name__)
app.config['JSONIFY_PRETTYPRINT_REGULAR'] = True

tasks = [
    {
        'id': 1,
        'title': 'Sample Task',
        'description': 'This is a sample task',
        'done': False,
        'created': '2023-10-01T10:00:00Z'
    }
]

@app.before_request
def log_request():
    app.logger.info(f"{request.method} {request.path} - {datetime.utcnow().isoformat()}Z")

@app.route('/tasks', methods=['GET', 'POST'])
def handle_tasks():
    if request.method == 'GET':
        return jsonify({'tasks': tasks})
    elif request.method == 'POST':
        if not request.is_json:
            abort(400)
        data = request.get_json()
        if 'title' not in data or not isinstance(data['title'], str):
            abort(400)
        new_task = {
            'id': tasks[-1]['id'] + 1 if tasks else 1,
            'title': data['title'],
            'description': data.get('description', ''),
            'done': False,
            'created': datetime.utcnow().isoformat() + 'Z'
        }
        tasks.append(new_task)
        return make_response(jsonify(new_task), 201)

@app.route('/tasks/<int:task_id>', methods=['GET', 'PUT', 'DELETE'])
def handle_task(task_id):
    task = next((t for t in tasks if t['id'] == task_id), None)
    if not task:
        abort(404)
    if request.method == 'GET':
        return jsonify(task)
    elif request.method == 'PUT':
        if not request.is_json:
            abort(400)
        data = request.get_json()
        if 'title' not in data or 'description' not in data or 'done' not in data:
            abort(400)
        task.update({
            'title': data['title'],
            'description': data['description'],
            'done': data['done']
        })
        return jsonify(task)
    elif request.method == 'DELETE':
        tasks.remove(task)
        return jsonify({'result': 'Task deleted'})

@app.errorhandler(400)
def bad_request(error):
    return make_response(jsonify({'error': 'Bad request', 'status': 400}), 400)

@app.errorhandler(404)
def not_found(error):
    return make_response(jsonify({'error': 'Not found', 'status': 404}), 404)

@app.errorhandler(500)
def internal_error(error):
    return make_response(jsonify({'error': 'Internal server error', 'status': 500}), 500)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)
