// src/main/java/com/example/UserRegistrationProcessor.java
package com.example;

import org.tinylog.Logger;
import com.opencsv.exceptions.CsvValidationException;
import com.opencsv.CSVReaderHeaderAware;
import java.io.FileReader;
import java.io.IOException;
import java.util.Map;

public class UserRegistrationProcessor {
    public static void main(String[] args) throws IOException, CsvValidationException {
        if (args.length == 0) {
            Logger.error("Application requires CSV file path as argument");
            System.exit(1);
        }

        try (CSVReaderHeaderAware reader = new CSVReaderHeaderAware(new FileReader(args[0]))) {
            Map<String, String> row;
            while ((row = reader.readMap()) != null) {
                validateUser(row);
            }
        }
    }

    private static void validateUser(Map<String, String> userData) {
        String name = userData.get("name");
        String email = userData.get("email");

        if (name == null || name.trim().isEmpty()) {
            Logger.error("Validation failed: Missing name field");
            return;
        }

        if (email == null || email.trim().isEmpty()) {
            Logger.error("Validation failed: Missing email field");
            return;
        }

        Logger.info("User registration successful for {}", email);
    }
}
