// UserProfileServiceImpl.java
package com.example.userprofile;

import io.grpc.Status;
import io.grpc.stub.StreamObserver;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

public class UserProfileServiceImpl extends UserProfileServiceGrpc.UserProfileServiceImplBase {
    private static final Logger logger = LoggerFactory.getLogger(UserProfileServiceImpl.class);
    private final ConcurrentHashMap<String, UserResponse> users = new ConcurrentHashMap<>();

    @Override
    public void createUser(CreateUserRequest request, StreamObserver<UserResponse> responseObserver) {
        logger.info("CreateUser request: {}", request);
        try {
            validateCreateRequest(request);
            String userId = UUID.randomUUID().toString();
            UserResponse response = UserResponse.newBuilder()
                    .setUserId(userId)
                    .setName(request.getName())
                    .setEmail(request.getEmail())
                    .setAddress(request.getAddress())
                    .build();
            users.put(userId, response);
            responseObserver.onNext(response);
            responseObserver.onCompleted();
        } catch (IllegalArgumentException e) {
            responseObserver.onError(Status.INVALID_ARGUMENT.withDescription(e.getMessage()).asRuntimeException());
        }
    }

    @Override
    public void getUser(GetUserRequest request, StreamObserver<UserResponse> responseObserver) {
        logger.info("GetUser request: {}", request);
        UserResponse user = users.get(request.getUserId());
        if (user == null) {
            responseObserver.onError(Status.NOT_FOUND.withDescription("User not found").asRuntimeException());
        } else {
            responseObserver.onNext(user);
            responseObserver.onCompleted();
        }
    }

    @Override
    public void updateUser(UpdateUserRequest request, StreamObserver<UserResponse> responseObserver) {
        logger.info("UpdateUser request: {}", request);
        try {
            validateUpdateRequest(request);
            UserResponse existingUser = users.get(request.getUserId());
            if (existingUser == null) {
                responseObserver.onError(Status.NOT_FOUND.withDescription("User not found").asRuntimeException());
                return;
            }
            UserResponse updatedUser = UserResponse.newBuilder(existingUser)
                    .setName(request.getName())
                    .setEmail(request.getEmail())
                    .setAddress(request.getAddress())
                    .build();
            users.put(request.getUserId(), updatedUser);
            responseObserver.onNext(updatedUser);
            responseObserver.onCompleted();
        } catch (IllegalArgumentException e) {
            responseObserver.onError(Status.INVALID_ARGUMENT.withDescription(e.getMessage()).asRuntimeException());
        }
    }

    private void validateCreateRequest(CreateUserRequest request) {
        if (request.getName().isEmpty() || request.getEmail().isEmpty()) {
            throw new IllegalArgumentException("Name and email are required");
        }
        validateEmail(request.getEmail());
    }

    private void validateUpdateRequest(UpdateUserRequest request) {
        if (request.getName().isEmpty() || request.getEmail().isEmpty()) {
            throw new IllegalArgumentException("Name and email are required");
        }
        validateEmail(request.getEmail());
    }

    private void validateEmail(String email) {
        if (!email.matches("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$")) {
            throw new IllegalArgumentException("Invalid email format");
        }
    }
}
