use bevy::prelude::*;
use bevy::window::WindowMode;

#[derive(Component)]
struct Player {
    speed: f32,
}

#[derive(Component)]
struct Obstacle;

#[derive(Component)]
struct Health {
    value: i32,
}

#[derive(Component)]
struct HealthText;

#[derive(Debug, Clone, Eq, PartialEq, Hash, States)]
enum GameState {
    Start,
    Game,
    GameOver,
}

fn main() {
    App::new()
        .add_plugins(DefaultPlugins.set(WindowPlugin {
            primary_window: Some(Window {
                title: "Bevy Game".into(),
                resolution: (800., 600.).into(),
                mode: WindowMode::Windowed,
                ..default()
            }),
            ..default()
        }))
        .add_state(GameState::Start)
        .add_systems(Startup, setup_camera)
        .add_systems(OnEnter(GameState::Start), setup_start_screen)
        .add_systems(OnExit(GameState::Start), despawn_screen)
        .add_systems(OnEnter(GameState::Game), setup_game)
        .add_systems(OnExit(GameState::Game), despawn_screen)
        .add_systems(OnEnter(GameState::GameOver), setup_game_over_screen)
        .add_systems(OnExit(GameState::GameOver), despawn_screen)
        .add_systems(
            Update,
            (
                handle_start_input,
                handle_gameover_input,
                player_movement,
                collision_detection,
                update_health_display,
                check_health,
            )
                .run_if(in_state(GameState::Game)),
        )
        .run();
}

fn setup_camera(mut commands: Commands) {
    commands.spawn(Camera2dBundle::default());
}

fn setup_start_screen(mut commands: Commands) {
    commands
        .spawn(NodeBundle {
            style: Style {
                width: Val::Percent(100.0),
                height: Val::Percent(100.0),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                flex_direction: FlexDirection::Column,
                ..default()
            },
            ..default()
        })
        .with_children(|parent| {
            parent.spawn(TextBundle::from_section(
                "My Game",
                TextStyle {
                    font_size: 64.0,
                    ..default()
                },
            ));
            parent.spawn(TextBundle::from_section(
                "Press SPACE to start",
                TextStyle {
                    font_size: 32.0,
                    ..default()
                },
            ));
        });
}

fn setup_game(mut commands: Commands, asset_server: Res<AssetServer>) {
    commands.spawn((
        SpriteBundle {
            sprite: Sprite {
                color: Color::BLUE,
                custom_size: Some(Vec2::new(30.0, 30.0)),
                ..default()
            },
            transform: Transform::from_xyz(0.0, 0.0, 1.0),
            ..default()
        },
        Player { speed: 300.0 },
        Health { value: 3 },
        Name::new("Player"),
    ));

    for _ in 0..5 {
        commands.spawn((
            SpriteBundle {
                sprite: Sprite {
                    color: Color::RED,
                    custom_size: Some(Vec2::new(40.0, 40.0)),
                    ..default()
                },
                transform: Transform::from_xyz(
                    rand::random::<f32>() * 600.0 - 300.0,
                    rand::random::<f32>() * 400.0 - 200.0,
                    1.0,
                ),
                ..default()
            },
            Obstacle,
            Name::new("Obstacle"),
        ));
    }

    commands.spawn((
        TextBundle::from_sections([
            TextSection::new(
                "Health: ",
                TextStyle {
                    font: asset_server.load("fonts/FiraSans-Bold.ttf"),
                    font_size: 32.0,
                    color: Color::WHITE,
                },
            ),
            TextSection::from_style(TextStyle {
                font: asset_server.load("fonts/FiraSans-Bold.ttf"),
                font_size: 32.0,
                color: Color::GOLD,
            }),
        ])
        .with_style(Style {
            position_type: PositionType::Absolute,
            top: Val::Px(10.0),
            left: Val::Px(10.0),
            ..default()
        }),
        HealthText,
    ));
}

fn setup_game_over_screen(mut commands: Commands) {
    commands
        .spawn(NodeBundle {
            style: Style {
                width: Val::Percent(100.0),
                height: Val::Percent(100.0),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                flex_direction: FlexDirection::Column,
                ..default()
            },
            ..default()
        })
        .with_children(|parent| {
            parent.spawn(TextBundle::from_section(
                "Game Over!",
                TextStyle {
                    font_size: 64.0,
                    ..default()
                },
            ));
            parent.spawn(TextBundle::from_section(
                "Press SPACE to restart",
                TextStyle {
                    font_size: 32.0,
                    ..default()
                },
            ));
        });
}

fn despawn_screen(mut commands: Commands, query: Query<Entity>) {
    for entity in query.iter() {
        commands.entity(entity).despawn();
    }
}

fn handle_start_input(
    keyboard_input: Res<Input<KeyCode>>,
    mut game_state: ResMut<NextState<GameState>>,
) {
    if keyboard_input.just_pressed(KeyCode::Space) {
        game_state.set(GameState::Game);
    }
}

fn handle_gameover_input(
    keyboard_input: Res<Input<KeyCode>>,
    mut game_state: ResMut<NextState<GameState>>,
) {
    if keyboard_input.just_pressed(KeyCode::Space) {
        game_state.set(GameState::Game);
    }
}

fn player_movement(
    mut query: Query<(&Player, &mut Transform)>,
    keyboard_input: Res<Input<KeyCode>>,
    time: Res<Time>,
) {
    let (player, mut transform) = query.single_mut();
    let mut direction = Vec3::ZERO;

    if keyboard_input.pressed(KeyCode::W) || keyboard_input.pressed(KeyCode::Up) {
        direction.y += 1.0;
    }
    if keyboard_input.pressed(KeyCode::S) || keyboard_input.pressed(KeyCode::Down) {
        direction.y -= 1.0;
    }
    if keyboard_input.pressed(KeyCode::A) || keyboard_input.pressed(KeyCode::Left) {
        direction.x -= 1.0;
    }
    if keyboard_input.pressed(KeyCode::D) || keyboard_input.pressed(KeyCode::Right) {
        direction.x += 1.0;
    }

    if direction != Vec3::ZERO {
        let move_speed = player.speed * time.delta_seconds();
        transform.translation += direction.normalize() * move_speed;
    }
}

fn collision_detection(
    player_query: Query<&Transform, With<Player>>,
    obstacle_query: Query<&Transform, With<Obstacle>>,
    mut health_query: Query<&mut Health>,
) {
    let player_transform = player_query.single();
    let player_size = Vec2::new(30.0, 30.0);

    for obstacle_transform in obstacle_query.iter() {
        let obstacle_size = Vec2::new(40.0, 40.0);
        let collision = player_transform.translation.x - player_size.x / 2.0
            < obstacle_transform.translation.x + obstacle_size.x / 2.0
            && player_transform.translation.x + player_size.x / 2.0
                > obstacle_transform.translation.x - obstacle_size.x / 2.0
            && player_transform.translation.y - player_size.y / 2.0
                < obstacle_transform.translation.y + obstacle_size.y / 2.0
            && player_transform.translation.y + player_size.y / 2.0
                > obstacle_transform.translation.y - obstacle_size.y / 2.0;

        if collision {
            if let Ok(mut health) = health_query.get_single_mut() {
                health.value = (health.value - 1).max(0);
            }
        }
    }
}

fn update_health_display(
    health_query: Query<&Health>,
    mut text_query: Query<&mut Text, With<HealthText>>,
) {
    let health = health_query.single();
    let mut text = text_query.single_mut();
    text.sections[1].value = health.value.to_string();
}

fn check_health(health_query: Query<&Health>, mut game_state: ResMut<NextState<GameState>>) {
    let health = health_query.single();
    if health.value <= 0 {
        game_state.set(GameState::GameOver);
    }
}
