import { component, h, render, state, effect } from 'whatsup'

const NoteInput = component(function*() {
    let title = ''
    let content = ''

    while (true) {
        yield (
            <div>
                <input 
                    type="text" 
                    value={title} 
                    onInput={e => title = e.target.value} 
                    placeholder="Title"
                />
                <textarea 
                    value={content} 
                    onInput={e => content = e.target.value} 
                    placeholder="Content"
                />
                <button onClick={() => {
                    const newNote = { title, content, id: Date.now() }
                    title = ''
                    content = ''
                    return newNote
                }}>
                    Add Note
                </button>
            </div>
        )
    }
})

const DeleteDialog = component(({ show, onConfirm, onCancel }) => (
    show && (
        <div>
            <p>Delete this note?</p>
            <button onClick={onConfirm}>Confirm</button>
            <button onClick={onCancel}>Cancel</button>
        </div>
    )
))

const NotesList = component(function*({ notes, onDelete }) {
    let selectedNote = null

    while (true) {
        yield (
            <div>
                {notes.map(note => (
                    <div key={note.id}>
                        <h3>{note.title}</h3>
                        <p>{note.content}</p>
                        <button onClick={() => selectedNote = note}>
                            Delete
                        </button>
                    </div>
                ))}
                <DeleteDialog 
                    show={!!selectedNote}
                    onConfirm={() => {
                        onDelete(selectedNote)
                        selectedNote = null
                    }}
                    onCancel={() => selectedNote = null}
                />
            </div>
        )
    }
})

const App = component(function*() {
    const notes = state([])
    const noteInput = NoteInput()

    effect(() => {
        const newNote = noteInput.clicked()
        if (newNote) notes.push(...notes.value, newNote)
    })

    const handleDelete = (note) => {
        notes.set(notes.value.filter(n => n.id !== note.id))
    }

    while (true) {
        yield (
            <div>
                <NoteInput ref={noteInput} />
                <NotesList notes={notes.value} onDelete={handleDelete} />
            </div>
        )
    }
})

render(<App />, document.getElementById('root'))
