#include "TemperatureSensor.h"

TemperatureSensor::TemperatureSensor() : threshold(0.0), testMode(false), testTemperature(0.0) {}

void TemperatureSensor::initialize(double threshold) {
    this->threshold = threshold;
}

double TemperatureSensor::readTemperature() const {
    if (testMode) {
        return testTemperature;
    }
    return 0.0;
}

bool TemperatureSensor::checkAlert() const {
    return readTemperature() > threshold;
}

void TemperatureSensor::setTestMode(bool enable, double temp) {
    testMode = enable;
    testTemperature = temp;
}
