```cpp
#include "CppUTest/TestHarness.h"
#include "CppUTest/CommandLineTestRunner.h"
#include "TemperatureSensor.h"
#include <limits>

TEST_GROUP(TemperatureSensorTest) {
    TemperatureSensor* sensor;

    void setup() {
        sensor = new TemperatureSensor();
    }

    void teardown() {
        delete sensor;
    }
};

TEST(TemperatureSensorTest, InitializationSetsThreshold) {
    sensor->initialize(30.0);
    sensor->setTestMode(true, 29.0);
    CHECK_FALSE(sensor->checkAlert());
    sensor->setTestMode(true, 31.0);
    CHECK(sensor->checkAlert());
}

TEST(TemperatureSensorTest, ReadTemperatureInTestMode) {
    sensor->setTestMode(true, 25.5);
    DOUBLES_EQUAL(25.5, sensor->readTemperature(), 0.001);
}

TEST(TemperatureSensorTest, ThresholdEdgeCases) {
    sensor->initialize(30.0);
    sensor->setTestMode(true, 30.0);
    CHECK_FALSE(sensor->checkAlert());
}

TEST(TemperatureSensorTest, MaxTemperatureAlert) {
    double maxTemp = std::numeric_limits<double>::max();
    sensor->initialize(maxTemp - 1.0);
    sensor->setTestMode(true, maxTemp);
    CHECK(sensor->checkAlert());
}

TEST(TemperatureSensorTest, MinTemperatureNoAlert) {
    double minTemp = std::numeric_limits<double>::lowest();
    sensor->initialize(minTemp + 1.0);
    sensor->setTestMode(true, minTemp);
    CHECK_FALSE(sensor->checkAlert());
}

int main(int argc, char** argv) {
    return CommandLineTestRunner::RunAllTests(argc, argv);
}
