import secrets
import string
import logging
from datetime import datetime
from cement import App, Controller, ex
from cement.utils import shell

class PasswordGeneratorController(Controller):
    class Meta:
        label = 'base'
        arguments = [
            (['-l', '--length'], {
                'type': int,
                'default': 16,
                'help': 'Password length (12-64)'
            }),
            (['-n', '--numbers'], {
                'action': 'store_true',
                'help': 'Include numbers'
            }),
            (['-s', '--symbols'], {
                'action': 'store_true',
                'help': 'Include special symbols'
            })
        ]

    @ex(help='Generate secure random password')
    def generate_password(self):
        try:
            length = self.app.pargs.length
            if not 12 <= length <= 64:
                raise ValueError("Password length must be between 12 and 64")

            chars = string.ascii_letters
            if self.app.pargs.numbers:
                chars += string.digits
            if self.app.pargs.symbols:
                chars += string.punctuation

            password = ''.join(secrets.choice(chars) for _ in range(length))

            self.app.log.info(f"Generated password at {datetime.now().isoformat()}")

            self.app.render({
                'password': password,
                'length': length,
                'options': {
                    'numbers': self.app.pargs.numbers,
                    'symbols': self.app.pargs.symbols
                }
            }, handler='json', colorize='CYAN')

        except Exception as e:
            self.app.log.error(str(e))
            self.app.render(str(e), colorize='RED')

class PasswordGenerator(App):
    class Meta:
        label = 'password-generator'
        base_controller = 'base'
        handlers = [PasswordGeneratorController]
        log_handler = 'colorlog'
        output_handler = 'json'

def main():
    with PasswordGenerator() as app:
        app.run()

if __name__ == '__main__':
    main()
