#include <CGraph/CGraph.h>
#include <opencv2/opencv.hpp>
#include <nlohmann/json.hpp>
#include <filesystem>
#include <chrono>
#include <mutex>

class ImageLoader : public CGraph::Node {
public:
    ImageLoader(const std::string& dir) : directory(dir) {}
    CStatus init() override {
        if (!std::filesystem::exists(directory)) {
            return CStatus("Directory not found");
        }
        return CStatus();
    }
    CStatus run() override {
        for (const auto& entry : std::filesystem::directory_iterator(directory)) {
            auto start = std::chrono::high_resolution_clock::now();
            std::string path = entry.path().string();
            cv::Mat img = cv::imread(path);
            auto end = std::chrono::high_resolution_clock::now();
            std::chrono::duration<double> elapsed = end - start;
            {
                std::lock_guard<std::mutex> lock(mtx_);
                total_time_ += elapsed.count();
                if (img.empty()) {
                    ++error_cnt_;
                    continue;
                }
                ++processed_cnt_;
            }
            CData data;
            data.set("image", img);
            data.set("path", path);
            sendOutput(data);
        }
        return CStatus();
    }
    int getProcessed() const { return processed_cnt_; }
    int getErrors() const { return error_cnt_; }
    double getTime() const { return total_time_; }

private:
    std::string directory;
    std::mutex mtx_;
    int processed_cnt_ = 0;
    int error_cnt_ = 0;
    double total_time_ = 0;
};

class ImageFilter : public CGraph::Node {
public:
    CStatus run() override {
        CData data = getInputData();
        cv::Mat img = data.get<cv::Mat>("image");
        auto start = std::chrono::high_resolution_clock::now();
        cv::cvtColor(img, img, cv::COLOR_BGR2GRAY);
        auto end = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed = end - start;
        {
            std::lock_guard<std::mutex> lock(mtx_);
            total_time_ += elapsed.count();
            ++processed_cnt_;
        }
        sendOutput(data);
        return CStatus();
    }
    int getProcessed() const { return processed_cnt_; }
    double getTime() const { return total_time_; }

private:
    std::mutex mtx_;
    int processed_cnt_ = 0;
    double total_time_ = 0;
};

class ImageSaver : public CGraph::Node {
public:
    ImageSaver(const std::string& dir) : output_dir(dir) {}
    CStatus init() override {
        std::filesystem::create_directories(output_dir);
        return CStatus();
    }
    CStatus run() override {
        CData data = getInputData();
        cv::Mat img = data.get<cv::Mat>("image");
        std::string path = data.get<std::string>("path");
        std::string filename = std::filesystem::path(path).filename().string();
        auto start = std::chrono::high_resolution_clock::now();
        bool success = cv::imwrite(output_dir + "/" + filename, img);
        auto end = std::chrono::high_resolution_clock::now();
        std::chrono::duration<double> elapsed = end - start;
        {
            std::lock_guard<std::mutex> lock(mtx_);
            total_time_ += elapsed.count();
            if (success) ++saved_cnt_;
            else ++error_cnt_;
        }
        return CStatus();
    }
    int getSaved() const { return saved_cnt_; }
    int getErrors() const { return error_cnt_; }
    double getTime() const { return total_time_; }

private:
    std::string output_dir;
    std::mutex mtx_;
    int saved_cnt_ = 0;
    int error_cnt_ = 0;
    double total_time_ = 0;
};

int main() {
    ImageLoader loader("input");
    ImageFilter filter;
    ImageSaver saver("output");

    CGraph::GPipeline pipeline;
    pipeline.addNode(&loader)
            .addNode(&filter)
            .addNode(&saver);

    pipeline.setThreadPoolSize(4);
    pipeline.run();
    pipeline.wait();

    nlohmann::json stats;
    stats["total_images"] = loader.getProcessed() + loader.getErrors();
    stats["loaded"] = loader.getProcessed();
    stats["load_errors"] = loader.getErrors();
    stats["filtered"] = filter.getProcessed();
    stats["saved"] = saver.getSaved();
    stats["save_errors"] = saver.getErrors();
    stats["load_time"] = loader.getTime();
    stats["filter_time"] = filter.getTime();
    stats["save_time"] = saver.getTime();

    std::cout << stats.dump(2) << std::endl;
    return 0;
}
