// InventoryServer.java
import io.grpc.Server;
import io.grpc.ServerBuilder;
import io.grpc.health.v1.HealthCheckResponse;
import io.grpc.protobuf.services.*;
import io.grpc.services.*;
import io.grpc.stub.StreamObserver;
import io.prometheus.client.CollectorRegistry;
import io.prometheus.client.Counter;
import io.prometheus.client.Histogram;
import io.prometheus.client.exporter.HTTPServer;

import javax.net.ssl.SSLException;
import java.io.File;
import java.io.IOException;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.TimeUnit;

public class InventoryServer {
    private static final ConcurrentHashMap<String, Integer> inventory = new ConcurrentHashMap<>();
    private static final Counter rpcCount = Counter.build()
            .name("rpc_count")
            .help("Total RPC Count")
            .labelNames("method")
            .register();
    private static final Histogram rpcDuration = Histogram.build()
            .name("rpc_duration_seconds")
            .help("RPC latency in seconds")
            .labelNames("method")
            .register();

    public static void main(String[] args) throws IOException, InterruptedException {
        CollectorRegistry registry = new CollectorRegistry();
        new HTTPServer(9090, registry, true);

        Server server = ServerBuilder.forPort(50051)
                .addService(new InventoryServiceImpl())
                .addService(new HealthStatusManager().getHealthService())
                .useTransportSecurity(
                        new File("server.crt"),
                        new File("server.pem"))
                .build();
        server.start();
        server.awaitTermination();
    }

    static class InventoryServiceImpl extends InventoryServiceGrpc.InventoryServiceImplBase {
        @Override
        public void updateStock(ProductStockUpdate request, StreamObserver<StockUpdateResponse> responseObserver) {
            Histogram.Timer timer = rpcDuration.labels("UpdateStock").startTimer();
            rpcCount.labels("UpdateStock").inc();

            inventory.merge(request.getProductId(), request.getQuantityChange(), Integer::sum);
            int current = inventory.get(request.getProductId());
            responseObserver.onNext(StockUpdateResponse.newBuilder()
                    .setProductId(request.getProductId())
                    .setCurrentStock(current)
                    .build());
            responseObserver.onCompleted();
            timer.observeDuration();
        }

        @Override
        public void alertLowStock(LowStockRequest request, StreamObserver<LowStockAlert> responseObserver) {
            rpcCount.labels("AlertLowStock").inc();
            Histogram.Timer timer = rpcDuration.labels("AlertLowStock").startTimer();

            inventory.forEach((productId, stock) -> {
                if (stock < request.getThreshold()) {
                    responseObserver.onNext(LowStockAlert.newBuilder()
                            .setProductId(productId)
                            .setCurrentStock(stock)
                            .setAlertMessage("Low stock alert")
                            .build());
                }
            });
            responseObserver.onCompleted();
            timer.observeDuration();
        }
    }
}
