        // Unary call
        blockingStub.updateStock(ProductStockUpdate.newBuilder()
                .setProductId("123")
                .setQuantityChange(-5)
                .build());

        // Server streaming
        InventoryServiceGrpc.InventoryServiceStub asyncStub = InventoryServiceGrpc.newStub(channel);
        asyncStub.alertLowStock(LowStockRequest.newBuilder().setThreshold(10).build(),
                new StreamObserver<LowStockAlert>() {
                    @Override
                    public void onNext(LowStockAlert alert) {
                        System.out.println("Alert: " + alert.getProductId() + " - " + alert.getCurrentStock());
