const useUserEngagement = () => {
  const [engagement, setEngagement] = useState({ time: 0, clicks: 0 });

  useEffect(() => {
    const timer = setInterval(() => {
      setEngagement(e => ({ ...e, time: e.time + 1 }));
    }, 1000);

