    window.addEventListener('click', clickHandler);

    return () => {
      clearInterval(timer);
      window.removeEventListener('click', clickHandler);
      // Send engagement data to API
    };
  }, []);

  return engagement;
};

// Error Boundary
class ErrorBoundary extends Component {
  state = { hasError: false };

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  componentDidCatch(error, info) {
    console.error('Error:', error, info);
  }

  render() {
    return this.state.hasError ? <div>Error loading content</div> : this.props.children;
  }
}

// Components
const CommentSection = ({ comments, onComment }) => {
  const [input, setInput] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    onComment(input);
    setInput('');
  };

  return (
    <div>
      {comments.map((c, i) => <div key={i}>{c}</div>)}
      <form onSubmit={handleSubmit}>
        <input value={input} onChange={(e) => setInput(e.target.value)} />
        <button type="submit">Comment</button>
      </form>
    </div>
  );
};

const Post = ({ post, onLike, onComment }) => {
  useUserEngagement();

  return (
    <div>
      <h3>{post.author}</h3>
      <p>{post.content}</p>
      <button onClick={() => onLike(post.id)}>Likes: {post.likes}</button>
      <CommentSection comments={post.comments} onComment={onComment} />
    </div>
  );
};

const Feed = () => {
  const [posts, setPosts] = useState([]);
  const [ws] = useState(() => new WebSocket('wss://api.example.com/feed'));
  const postGenerator = useRef(null);

  function* createPostGenerator() {
    let page = 0;
    while (true) {
      const res = yield fetch(`/api/posts?page=${page++}`).then(r => r.json());
      if (res?.length) yield res;
    }
  }

  useEffect(() => {
    postGenerator.current = createPostGenerator();
    postGenerator.current.next().value.then(data => setPosts(data));

    ws.onmessage = (e) => {
      const msg = JSON.parse(e.data);
      setPosts(p => p.map(post => post.id === msg.id ? { ...post, ...msg } : post));
    };

    const handleScroll = () => {
      if (window.innerHeight + window.scrollY >= document.body.offsetHeight - 500) {
        postGenerator.current.next().value.then(data => setPosts(p => [...p, ...data]));
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [ws]);

  const handleLike = (id) => ws.send(JSON.stringify({ type: 'like', id }));
  const handleComment = (id, text) => ws.send(JSON.stringify({ type: 'comment', id, text }));

  return (
    <ErrorBoundary>
      {posts.map(post => (
        <Post
          key={post.id}
          post={post}
          onLike={() => handleLike(post.id)}
          onComment={(text) => handleComment(post.id, text)}
        />
      ))}
    </ErrorBoundary>
  );
};

export default Feed;
