package main

import (
	"context"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/dgrijalva/jwt-go"
	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/jwtauth"
	"github.com/go-chi/render"
	"github.com/ulule/limiter/v3"
	middlewareLimiter "github.com/ulule/limiter/v3/drivers/middleware/stdlib"
	"gorm.io/driver/postgres"
	"gorm.io/gorm"
	"gorm.io/gorm/logger"
)

var (
	db         *gorm.DB
	tokenAuth  *jwtauth.JWTAuth
	rateLimiter *middlewareLimiter.Middleware
)

type User struct {
	gorm.Model
	Email    string `gorm:"uniqueIndex"`
	Password string
	Role     string
}

type Job struct {
	gorm.Model
	Title       string
	Description string
	Location    string
	Salary      float64
	EmployerID  uint
}

func main() {
	dsn := "host=localhost user=postgres password=postgres dbname=jobboard port=5432 sslmode=disable"
	var err error
	db, err = gorm.Open(postgres.Open(dsn), &gorm.Config{
		Logger: logger.Default.LogMode(logger.Info),
	})
	if err != nil {
		log.Fatal(err)
	}

	db.AutoMigrate(&User{}, &Job{})

	tokenAuth = jwtauth.New("HS256", []byte(os.Getenv("JWT_SECRET")), nil)

	rate, _ := limiter.NewRateFromFormatted("5-M")
	rateLimiter = middlewareLimiter.NewMiddleware(limiter.NewMemoryStore(), rate)

	r := chi.NewRouter()
	r.Use(middleware.Logger)
	r.Use(middleware.Recoverer)
	r.Use(render.SetContentType(render.ContentTypeJSON))

	r.Group(func(r chi.Router) {
		r.Use(rateLimiter.Handler)
		r.Post("/auth/register", register)
		r.Post("/auth/login", login)
	});

	r.Group(func(r chi.Router) {
		r.Use(jwtauth.Verifier(tokenAuth))
		r.Use(jwtauth.Authenticator)

		r.Get("/jobs", listJobs)
		r.Get("/jobs/search", searchJobs)

		r.Group(func(r chi.Router) {
			r.Use(requireEmployer)
			r.Post("/jobs", createJob)
			r.Put("/jobs/{id}", updateJob)
			r.Delete("/jobs/{id}", deleteJob)
		})
	})

	http.ListenAndServe(":8080", r)
}

func register(w http.ResponseWriter, r *http.Request) {
	var req struct {
		Email    string `validate:"required,email"`
		Password string `validate:"required,min=8"`
		Role     string `validate:"required,oneof=employer candidate"`
	}
	if err := render.DecodeJSON(r.Body, &req); err != nil {
		renderError(w, r, http.StatusBadRequest, "Invalid request")
		return
	}

	user := User{Email: req.Email, Password: req.Password, Role: req.Role}
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	if result := db.WithContext(ctx).Create(&user); result.Error != nil {
		renderError(w, r, http.StatusConflict, "User already exists")
		return
	}

	render.Status(r, http.StatusCreated)
	render.JSON(w, r, map[string]interface{}{"id": user.ID})
}

func login(w http.ResponseWriter, r *http.Request) {
	var creds struct {
		Email    string `validate:"required,email"`
		Password string `validate:"required"`
	}
	if err := render.DecodeJSON(r.Body, &creds); err != nil {
		renderError(w, r, http.StatusBadRequest, "Invalid request")
		return
	}

	var user User
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	if result := db.WithContext(ctx).Where("email = ?", creds.Email).First(&user); result.Error != nil {
		renderError(w, r, http.StatusUnauthorized, "Invalid credentials")
		return
	}

	if user.Password != creds.Password {
		renderError(w, r, http.StatusUnauthorized, "Invalid credentials")
		return
	}

	claims := jwt.MapClaims{"sub": user.ID, "role": user.Role, "exp": time.Now().Add(time.Hour * 24).Unix()}
	_, tokenString, _ := tokenAuth.Encode(claims)

	render.JSON(w, r, map[string]string{"token": tokenString})
}

func createJob(w http.ResponseWriter, r *http.Request) {
	var jobReq struct {
		Title       string  `validate:"required"`
		Description string  `validate:"required"`
		Location    string  `validate:"required"`
		Salary      float64 `validate:"required"`
	}
	if err := render.DecodeJSON(r.Body, &jobReq); err != nil {
		renderError(w, r, http.StatusBadRequest, "Invalid request")
		return
	}

	_, claims, _ := jwtauth.FromContext(r.Context())
	job := Job{
		Title:       jobReq.Title,
		Description: jobReq.Description,
		Location:    jobReq.Location,
		Salary:      jobReq.Salary,
		EmployerID:  uint(claims["sub"].(float64)),
	}

	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	if result := db.WithContext(ctx).Create(&job); result.Error != nil {
		renderError(w, r, http.StatusInternalServerError, "Error creating job")
		return
	}

	render.Status(r, http.StatusCreated)
	render.JSON(w, r, job)
}

func searchJobs(w http.ResponseWriter, r *http.Request) {
	query := r.URL.Query()
	filter := db.Model(&Job{})

	if loc := query.Get("location"); loc != "" {
		filter = filter.Where("location ILIKE ?", "%"+loc+"%")
	}
	if min := query.Get("min_salary"); min != "" {
		filter = filter.Where("salary >= ?", min)
	}
	if max := query.Get("max_salary"); max != "" {
		filter = filter.Where("salary <= ?", max)
	}
	if kw := query.Get("keywords"); kw != "" {
		filter = filter.Where("title ILIKE ? OR description ILIKE ?", "%"+kw+"%", "%"+kw+"%")
	}

	var jobs []Job
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	if result := filter.WithContext(ctx).Find(&jobs); result.Error != nil {
		renderError(w, r, http.StatusInternalServerError, "Search failed")
		return
	}

	render.JSON(w, r, jobs)
}

func requireEmployer(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		_, claims, _ := jwtauth.FromContext(r.Context())
		if claims["role"] != "employer" {
			renderError(w, r, http.StatusForbidden, "Requires employer role")
			return
		}
		next.ServeHTTP(w, r)
	})
}

func renderError(w http.ResponseWriter, r *http.Request, status int, message string) {
	render.Status(r, status)
	render.JSON(w, r, map[string]interface{}{"error": message})
}

// Additional handlers (updateJob, deleteJob, listJobs) and validation middleware omitted for brevity
