        commands.spawn((
            SpriteBundle {
                texture: asset_server.load("projectile.png"),
                transform: Transform::from_translation(transform.translation + Vec3::Y * 50.0),
                ..default()
            },
            Projectile,
            Velocity(Vec3::Y * 1000.0),
