<script>
export default {
  data() {
    return {
      tasks: [],
      selectedStatus: 'all',
      showForm: false,
      isEditing: false,
      currentTask: this.emptyTask()
    }
  },
  computed: {
    filteredTasks() {
      if (this.selectedStatus === 'all') return this.tasks
      return this.tasks.filter(task => task.status === this.selectedStatus)
    }
  },
  methods: {
    emptyTask() {
      return {
        id: null,
        title: '',
        description: '',
        status: 'To Do',
        dueDate: ''
      }
    },
    openAddForm() {
      this.currentTask = this.emptyTask()
      this.isEditing = false
      this.showForm = true
    },
    startEdit(task) {
      this.currentTask = { ...task }
      this.isEditing = true
      this.showForm = true
    },
    saveTask() {
      if (this.isEditing) {
        const index = this.tasks.findIndex(t => t.id === this.currentTask.id)
        this.tasks.splice(index, 1, this.currentTask)
      } else {
        this.currentTask.id = Date.now()
        this.tasks.push(this.currentTask)
      }
      this.cancelForm()
    },
    deleteTask(id) {
      this.tasks = this.tasks.filter(task => task.id !== id)
    },
    cancelForm() {
      this.showForm = false
      this.currentTask = this.emptyTask()
    }
  }
}
